    },
    "evidence_coverage": {
      "type": "object"
    },
    "analysis_quality": {
      "type": "object"
    },
    "incomplete_reason": {
      "type": "string",
      "minLength": 1
    },
    "suspected_locations": {
      "type": "array",
      "items": {}
    },
    "root_cause_hypothesis": {
      "type": "string",
